// Aggregate risk indicators from multiple rows into structured object
const items = $input.all();

// Initialize aggregated risk data structure
const aggregatedRisk = {
  supplier: {
    totalSuppliers: 0,
    highRiskSuppliers: 0,
    averageLeadTime: 0,
    qualityIssues: 0
  },
  logistics: {
    delayedShipments: 0,
    totalShipments: 0,
    averageDelayDays: 0,
    routeDisruptions: 0
  },
  inventory: {
    lowStockItems: 0,
    totalItems: 0,
    stockoutRisk: 0,
    averageStockLevel: 0
  },
  rawData: []
};

// Process each row of risk data
for (const item of items) {
  const data = item.json;

  // Aggregate supplier metrics
  if (data.supplierRiskScore !== undefined) {
    aggregatedRisk.supplier.totalSuppliers++;
    if (data.supplierRiskScore > 70) {
      aggregatedRisk.supplier.highRiskSuppliers++;
    }
  }

  if (data.leadTime !== undefined) {
    aggregatedRisk.supplier.averageLeadTime += data.leadTime;
  }

  if (data.qualityIssue === true || data.qualityIssue === 'true') {
    aggregatedRisk.supplier.qualityIssues++;
  }

  // Aggregate logistics metrics
  if (data.shipmentStatus !== undefined) {
    aggregatedRisk.logistics.totalShipments++;
    if (data.shipmentStatus === 'delayed') {
      aggregatedRisk.logistics.delayedShipments++;
    }
  }

  if (data.delayDays !== undefined && data.delayDays > 0) {
    aggregatedRisk.logistics.averageDelayDays += data.delayDays;
  }

  if (data.routeDisruption === true || data.routeDisruption === 'true') {
    aggregatedRisk.logistics.routeDisruptions++;
  }

  // Aggregate inventory metrics
  if (data.stockLevel !== undefined) {
    aggregatedRisk.inventory.totalItems++;
    aggregatedRisk.inventory.averageStockLevel += data.stockLevel;

    if (data.stockLevel < data.reorderPoint) {
      aggregatedRisk.inventory.lowStockItems++;
    }
  }

  if (data.stockoutRisk !== undefined) {
    aggregatedRisk.inventory.stockoutRisk += data.stockoutRisk;
  }

  // Store raw data for reference
  aggregatedRisk.rawData.push(data);
}

// Calculate averages
if (aggregatedRisk.supplier.totalSuppliers > 0) {
  aggregatedRisk.supplier.averageLeadTime = 
    aggregatedRisk.supplier.averageLeadTime / aggregatedRisk.supplier.totalSuppliers;
}

if (aggregatedRisk.logistics.delayedShipments > 0) {
  aggregatedRisk.logistics.averageDelayDays = 
    aggregatedRisk.logistics.averageDelayDays / aggregatedRisk.logistics.delayedShipments;
}

if (aggregatedRisk.inventory.totalItems > 0) {
  aggregatedRisk.inventory.averageStockLevel = 
    aggregatedRisk.inventory.averageStockLevel / aggregatedRisk.inventory.totalItems;
  aggregatedRisk.inventory.stockoutRisk = 
    aggregatedRisk.inventory.stockoutRisk / aggregatedRisk.inventory.totalItems;
}

// Calculate overall risk score
aggregatedRisk.overallRiskScore = (
  (aggregatedRisk.supplier.highRiskSuppliers / Math.max(aggregatedRisk.supplier.totalSuppliers, 1)) * 40 +
  (aggregatedRisk.logistics.delayedShipments / Math.max(aggregatedRisk.logistics.totalShipments, 1)) * 30 +
  (aggregatedRisk.inventory.lowStockItems / Math.max(aggregatedRisk.inventory.totalItems, 1)) * 30
);

aggregatedRisk.timestamp = new Date().toISOString();

// Return with riskData field instead of at root level
return [{ json: { riskData: aggregatedRisk } }];

